function stripDiacritics(text) {
  return text
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function normalizeText(text) {
  if (!text) return "";
  return stripDiacritics(String(text).toLowerCase())
    .replace(/[^\p{L}\p{N}\s]/gu, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function stemToken(token) {
  let t = token;
  const suffixes = [
    "owego", "owej", "owemu", "owym", "owych", "owie", "ami", "ach", "ego", "emu", "owa", "owe", "owy", "ow", "ami", "ach", "ie", "ia", "em", "om", "ow", "a", "e", "y", "u"
  ];

  for (const suffix of suffixes) {
    if (t.length > suffix.length + 2 && t.endsWith(suffix)) {
      t = t.slice(0, -suffix.length);
      break;
    }
  }
  return t;
}

function tokenize(text) {
  return normalizeText(text)
    .split(" ")
    .filter(Boolean)
    .map(stemToken);
}

function clampOutput(output) {
  if (Buffer.byteLength(output, "utf8") <= MAX_OUTPUT_BYTES) {
    return output;
  }

  let trimmed = output;
  while (Buffer.byteLength(trimmed, "utf8") > MAX_OUTPUT_BYTES && trimmed.length > 4) {
    trimmed = trimmed.slice(0, -1);
  }
  return trimmed;
}

const cityNameByCode = new Map(citiesData.map((city) => [city.code, city.name]));
const cityCodesByItemCode = new Map();

for (const row of connectionsData) {
  if (!row.itemCode || !row.cityCode) continue;
  if (!cityCodesByItemCode.has(row.itemCode)) {
    cityCodesByItemCode.set(row.itemCode, new Set());
  }
  cityCodesByItemCode.get(row.itemCode).add(row.cityCode);
}

const indexedItems = itemsData.map((item) => {
  const tokens = tokenize(item.name);
  return {
    ...item,
    normalizedName: normalizeText(item.name),
    tokens,
    tokenSet: new Set(tokens)
  };
});

function findBestItem(query) {
  const normalizedQuery = normalizeText(query);
  const queryTokens = tokenize(query);
  if (!normalizedQuery) return null;

  let best = null;
  let bestScore = 0;

  for (const item of indexedItems) {
    let score = 0;

    if (normalizedQuery.includes(item.normalizedName)) {
      score += 1000;
    }

    for (const token of queryTokens) {
      if (item.tokenSet.has(token)) {
        score += token.length >= 4 ? 3 : 1;
      }
      if (item.normalizedName.includes(token)) {
        score += 1;
      }
    }

    const coverage = queryTokens.length
      ? queryTokens.filter((t) => item.tokenSet.has(t)).length / queryTokens.length
      : 0;
    score += coverage * 10;

    if (score > bestScore) {
      bestScore = score;
      best = item;
    }
  }

  return bestScore >= 2 ? best : null;
}

function makeResponse(statusCode, payload) {
  return {
    statusCode,
    headers: { "Content-Type": "application/json; charset=utf-8" },
    body: JSON.stringify(payload)
  };
}

function sendJson(res, statusCode, payload) {
  if (res && typeof res.json === "function") {
    res.statusCode = statusCode;
    return res.json(payload);
  }
  return makeResponse(statusCode, payload);
}

function extractMethod(req) {
  return req && typeof req.method === "string" ? req.method.toUpperCase() : "";
}

function extractParams(req) {
  if (!req) return "";
  if (req.body && typeof req.body.params === "string") return req.body.params;
  if (typeof req.body === "string") {
    try {
      const parsed = JSON.parse(req.body);
      if (parsed && typeof parsed.params === "string") return parsed.params;
    } catch (_) {
      return "";
    }
  }
  return "";
}

module.exports = function handler(req, res) {
  console.log("Handler started");
  if (extractMethod(req) !== "POST") {
    return sendJson(res, 405, { output: "Method Not Allowed" });
  }

  try {
    const params = extractParams(req);
    console.log("Params received:", params);
    if (!params.trim()) {
      return sendJson(res, 400, {
        output: "Podaj tekst w polu params, np. 'potrzebuję rezystora 1 ohm'."
      });
    }

    const bestItem = findBestItem(params);
    console.log("Best item found:", bestItem);
    if (!bestItem) {
      const output = clampOutput("Nie znalazlem przedmiotu. Sprobuj podac wiecej detali, np. 'rezystor metalizowany 1 ohm'.");
      console.log("Returning response");
      return sendJson(res, 200, { output });
    }

    const cityCodesSet = cityCodesByItemCode.get(bestItem.code);
    if (!cityCodesSet || cityCodesSet.size === 0) {
      const output = clampOutput(`Brak miast dla przedmiotu: ${bestItem.name}. Sprobuj innej frazy.`);
      return sendJson(res, 200, { output });
    }

    const cityNames = Array.from(cityCodesSet)
      .map((code) => cityNameByCode.get(code))
      .filter(Boolean)
      .sort((a, b) => a.localeCompare(b, "pl"));
    console.log("Cities found:", cityNames);

    if (cityNames.length === 0) {
      const output = clampOutput(`Brak poprawnych mapowan miast dla przedmiotu: ${bestItem.name}.`);
      console.log("Returning response");
      return sendJson(res, 200, { output });
    }

    let output = `Miasta: ${cityNames.join(", ")}`;
    output = clampOutput(output);
    if (Buffer.byteLength(output, "utf8") < 4) output = "Brak";

    console.log("Returning response");
    return sendJson(res, 200, { output });
  } catch (error) {
    console.error("Handler error:", error);
    console.error("Handler error stack:", error && error.stack ? error.stack : "no stack");
    const output = clampOutput("Wystapil blad serwera podczas wyszukiwania.");
    console.log("Returning response");
    return sendJson(res, 500, { output });
  }
};
